document.addEventListener("DOMContentLoaded", function () {
  if (localStorage.getItem("scrollToGallery") === "true") {
    // Clear the flag
    localStorage.removeItem("scrollToGallery");

    // Perform the scroll
    $("html, body").animate(
      {
        scrollTop: $("#gallery").offset().top,
      },
      2000,
      "swing"
    );
  }
});
